_BG_IMAGE_B64 = ""

FONT_TITLE = ("Segoe UI", 22, "bold")

def _load_bg_image(filename, width, height):
    """Charge l'image de fond depuis base64 embarquée."""
    try:
        import base64 as _b64, io as _io
        from PIL import Image as _Img, ImageTk as _ITk
        img_data = _b64.b64decode(_BG_IMAGE_B64)
        img = _Img.open(_io.BytesIO(img_data)).resize((width, height), _Img.LANCZOS)
        return _ITk.PhotoImage(img)
    except Exception as e:
        print(f"Erreur chargement fond: {e}")
        return None

def _resolve_asset_path(filename):
    base_dirs = []
    if getattr(sys, 'frozen', False):
        base_dirs.append(getattr(sys, "_MEIPASS", ""))
    current_dir = os.path.dirname(os.path.abspath(__file__))
    base_dirs.append(current_dir)
    base_dirs.append(os.path.abspath(os.path.join(current_dir, "..", "ressource")))
    for base in base_dirs:
        if not base:
            continue
        candidate = os.path.join(base, filename)
        if os.path.exists(candidate):
            return candidate
    return None

def _load_asset_image(filename, width, height, cover=False):
    try:
        from PIL import Image as _Img, ImageOps as _Ops, ImageTk as _ITk
        path = _resolve_asset_path(filename)
        if not path:
            return None
        img = _Img.open(path).convert("RGBA")
        if cover:
            canvas = _Ops.fit(img, (width, height), method=_Img.LANCZOS, centering=(0.5, 0.45))
        else:
            bg = img.getpixel((0, 0))
            img.thumbnail((width, height), _Img.LANCZOS)
            canvas = _Img.new("RGBA", (width, height), (bg[0], bg[1], bg[2], 255))
            x = (width - img.width) // 2
            y = (height - img.height) // 2
            canvas.alpha_composite(img, (x, y))
        return _ITk.PhotoImage(canvas)
    except Exception:
        return None

def _set_windows_app_user_model_id(app_id):
    try:
        ctypes.windll.shell32.SetCurrentProcessExplicitAppUserModelID(app_id)
    except Exception:
        pass


def _get_window_long_ptr(hwnd, index):
    getter = getattr(ctypes.windll.user32, "GetWindowLongPtrW", None)
    if getter is None:
        getter = ctypes.windll.user32.GetWindowLongW
    return getter(hwnd, index)


def _set_window_long_ptr(hwnd, index, value):
    setter = getattr(ctypes.windll.user32, "SetWindowLongPtrW", None)
    if setter is None:
        setter = ctypes.windll.user32.SetWindowLongW
    return setter(hwnd, index, value)


def _apply_window_icon(root, ico_filename, png_filename=None):
    try:
        ico_path = _resolve_asset_path(ico_filename)
        if not ico_path:
            return
        root.iconbitmap(ico_path)
        try:
            from PIL import Image as _Img, ImageTk as _ITk
            icon_path = _resolve_asset_path(png_filename) if png_filename else ico_path
            icon_img = _Img.open(icon_path)
            root._window_icon_photo = _ITk.PhotoImage(icon_img)
            root.iconphoto(True, root._window_icon_photo)
        except Exception:
            pass
    except Exception:
        pass


def _configure_pygame_helper_window(root, icon_filename=None):
    try:
        pygame.display.set_caption(f"{APP_NAME} Input Helper")
    except Exception:
        pass
    try:
        icon_path = _resolve_asset_path(icon_filename) if icon_filename else None
        if icon_path:
            pygame.display.set_icon(pygame.image.load(icon_path))
    except Exception:
        pass
    return


def _init_pygame_helper_window(root, icon_filename=None):
    try:
        pygame.display.set_mode((1, 1), pygame.NOFRAME)
    except Exception:
        pygame.display.set_mode((1, 1), pygame.NOFRAME)
    _configure_pygame_helper_window(root, icon_filename)
    try:
        pygame.display.iconify()
    except Exception:
        pass

def creer_fond_racing(parent, width=700, height=660, banner=False):
    """Pose une image de fond sur le widget parent via un Label."""
    filename = "installer_bg_banner.png" if banner else "installer_bg.png"
    h = 120 if banner else height
    photo = _load_bg_image(filename, width, h)
    if photo:
        lbl = tk.Label(parent, image=photo, bd=0)
        lbl.image = photo  # garder référence
        lbl.place(x=0, y=0, width=width, height=h)
        lbl.lower()
        return lbl
    return None

