def _list_windows_tts_voices():
    try:
        voices = []
        seen = set()
        import comtypes
        import comtypes.client
        comtypes.CoInitialize()
        try:
            speaker = comtypes.client.CreateObject("SAPI.SpVoice", dynamic=True)
            for tokens in (speaker.GetVoices(),):
                try:
                    count = int(tokens.Count)
                except Exception:
                    count = 0
                for i in range(count):
                    try:
                        name = str(tokens.Item(i).GetDescription()).strip()
                    except Exception:
                        continue
                    if name and name not in seen:
                        seen.add(name)
                        voices.append(name)
            try:
                category = comtypes.client.CreateObject("SAPI.SpObjectTokenCategory", dynamic=True)
                category.SetId(r"HKEY_LOCAL_MACHINE\SOFTWARE\Microsoft\Speech_OneCore\Voices", False)
                tokens = category.EnumerateTokens()
                try:
                    count = int(tokens.Count)
                except Exception:
                    count = 0
                for i in range(count):
                    try:
                        name = str(tokens.Item(i).GetDescription()).strip()
                    except Exception:
                        continue
                    if name and name not in seen:
                        seen.add(name)
                        voices.append(name)
            except Exception:
                pass
        finally:
            try:
                comtypes.CoUninitialize()
            except Exception:
                pass
        return voices
    except Exception:
        return []

def _speak_windows_tts_preview(text, voice_name=""):
    def _runner():
        try:
            import comtypes
            import comtypes.client

            def _norm(value):
                return " ".join((value or "").strip().lower().split())

            def _keys(label):
                keys = {_norm(label)} if _norm(label) else set()
                if " - " in (label or ""):
                    short = _norm(label.split(" - ", 1)[0])
                    if short:
                        keys.add(short)
                return keys

            comtypes.CoInitialize()
            try:
                voice = comtypes.client.CreateObject("SAPI.SpVoice", dynamic=True)
                voice_map = {}

                def _register(tokens):
                    try:
                        count = int(tokens.Count)
                    except Exception:
                        count = 0
                    for i in range(count):
                        try:
                            tok = tokens.Item(i)
                            desc = str(tok.GetDescription())
                        except Exception:
                            continue
                        for key in _keys(desc):
                            voice_map.setdefault(key, tok)

                _register(voice.GetVoices())
                try:
                    category = comtypes.client.CreateObject("SAPI.SpObjectTokenCategory", dynamic=True)
                    category.SetId(r"HKEY_LOCAL_MACHINE\SOFTWARE\Microsoft\Speech_OneCore\Voices", False)
                    _register(category.EnumerateTokens())
                except Exception:
                    pass

                token = voice_map.get(_norm(voice_name))
                if token is not None:
                    try:
                        voice.Voice = token
                    except Exception:
                        pass
                if text:
                    voice.Speak(text)
            finally:
                try:
                    comtypes.CoUninitialize()
                except Exception:
                    pass
        except Exception:
            pass

    threading.Thread(
        target=_runner,
        daemon=True,
    ).start()

def _match_tts_voice_name(selected_voice, available_voices):
    value = (selected_voice or "").strip()
    if not value:
        return ""
    if value in available_voices:
        return value
    low = value.lower()
    for candidate in available_voices:
        cand_low = candidate.lower()
        if cand_low == low or cand_low.startswith(low) or low in cand_low:
            return candidate
    return ""

