def get_exe_path():
    return os.path.join(get_runtime_install_dir(), EXE_NAME)

def get_runtime_install_dir():
    if CONFIGURE_ONLY:
        current_path = sys.executable if getattr(sys, 'frozen', False) else os.path.abspath(__file__)
        current_dir = os.path.dirname(os.path.abspath(current_path))
        parent_dir = os.path.dirname(current_dir)
        if os.path.basename(current_dir).lower() == "configurator" and os.path.exists(parent_dir):
            return parent_dir
    return INSTALL_DIR


def is_admin():
    try:
        return ctypes.windll.shell32.IsUserAnAdmin()
    except:
        return False


class InstallerApp:
    def __init__(self, root):
        self.root = root
        self.root.title(f"{APP_NAME} — Config")
        self.root.geometry(f"{WINDOW_WIDTH}x{WINDOW_HEIGHT}")
        self.root.resizable(False, False)
        self.root.configure(bg=BG_DARK)
        self.root.protocol("WM_DELETE_WINDOW", self.on_close)
        _apply_window_icon(self.root, WINDOW_ICON_ICO, WINDOW_ICON_PNG)

        self.root.update_idletasks()
        sw = self.root.winfo_screenwidth()
        sh = self.root.winfo_screenheight()
        x = (sw - WINDOW_WIDTH) // 2
        y = max(20, (sh - WINDOW_HEIGHT) // 2)
        self.root.geometry(f"{WINDOW_WIDTH}x{WINDOW_HEIGHT}+{x}+{y}")
        self.root.update_idletasks()

        self.lang         = "fr"   # défaut
        self.import_music = tk.BooleanVar(value=True)
        self.desktop_sc   = tk.BooleanVar(value=True)
        self.use_shortcuts    = tk.BooleanVar(value=True)
        self.notifications_on = tk.BooleanVar(value=True)
        self.notif_volume = tk.BooleanVar(value=True)
        self.notif_switch = tk.BooleanVar(value=True)
        self.notif_playlist = tk.BooleanVar(value=False)
        self.notif_radio = tk.BooleanVar(value=True)
        self.music_sources = []
        self.raccourcis   = {"modifier":None,"suivant":None,"volume_up":None,"volume_down":None,"switch":None}
        self.lord_button_binding = None
        self._capturing   = False
        self._joysticks   = []
        self._controllers = []
        self._device_catalog = []
        self._tts_voices = _list_windows_tts_voices()
        self.tts_voice = tk.StringVar(value=self._tts_voices[0] if self._tts_voices else "")

        pygame.init()
        try:
            if pygame.mixer.get_init():
                pygame.mixer.quit()
        except Exception:
            pass
        _init_pygame_helper_window(self.root, WINDOW_ICON_PNG)
        pygame.joystick.init()
        self._init_controller_layer()
        self._load_existing_config()
        self._ensure_default_music_source()

        self._frame_lang()

    def t(self, key):
        return T.get(self.lang, T["fr"]).get(key, key)

    def _notif_t(self, key):
        bucket = NOTIFICATION_UI_TEXTS.get(self.lang, NOTIFICATION_UI_TEXTS["fr"])
        return bucket.get(key, NOTIFICATION_UI_TEXTS["en"].get(key, key))

    def _notification_vars(self):
        return [
            self.notif_volume,
            self.notif_switch,
            self.notif_playlist,
            self.notif_radio,
        ]

    def _notification_master_enabled(self):
        return any(var.get() for var in self._notification_vars())

    def _apply_notification_legacy_default(self, enabled):
        if enabled:
            self.notif_volume.set(True)
            self.notif_switch.set(True)
            self.notif_playlist.set(True)
            self.notif_radio.set(True)
        else:
            for var in self._notification_vars():
                var.set(False)
        self.notifications_on.set(bool(enabled))

    def _selected_tts_voice(self):
        value = (self.tts_voice.get() or "").strip()
        if not value or value == self._notif_t("voice_none"):
            return ""
        return value

