    def _lord_mode_active(self):
        return self.use_shortcuts.get() and isinstance(self.lord_button_binding, dict)

    def _build_lord_shortcuts(self):
        if not isinstance(self.lord_button_binding, dict):
            return {}
        gesture_map = {
            "suivant": "press",
            "switch": "double_tap",
            "volume_up": "hold",
            "volume_down": "double_tap_hold",
        }
        data = {}
        for key, gesture in gesture_map.items():
            binding = dict(self.lord_button_binding)
            binding["gesture"] = gesture
            data[key] = binding
        return data

    def _effective_shortcuts(self):
        if self._lord_mode_active():
            return self._build_lord_shortcuts()
        return {
            key: value
            for key, value in self.raccourcis.items()
            if isinstance(value, dict)
        }

    def _frame_notifications_back_target(self):
        if not self.use_shortcuts.get():
            return self._frame_options
        if self._lord_mode_active():
            return self._frame_lord_of_the_bouton
        return self._frame_shortcuts

    def _decode_binding_value(self, raw, modifier=False):
        raw = (raw or "").strip()
        if not raw:
            return None
        if raw.lower() == "skip":
            return "skip"
        if raw.startswith("{"):
            try:
                data = json.loads(raw)
                if isinstance(data, dict):
                    data.setdefault("version", INPUT_BINDING_VERSION)
                    data["gesture"] = "hold" if modifier else data.get("gesture", "press")
                    return data
            except Exception:
                return None

        parts = raw.lower().split(":")
        if len(parts) < 2:
            return None

        gesture = "hold" if modifier else "press"
        if parts[0] == "key":
            try:
                return {
                    "version": 1,
                    "device_kind": "keyboard_mouse",
                    "input_type": "key",
                    "key": int(parts[1]),
                    "gesture": gesture,
                }
            except Exception:
                return None

        if parts[0] == "joy" and len(parts) >= 4:
            try:
                legacy_joy_id = int(parts[1])
                joy_type = parts[2]
                if joy_type == "button":
                    return {
                        "version": 1,
                        "device_kind": "legacy_joystick",
                        "legacy_joy_id": legacy_joy_id,
                        "input_type": "joy_button",
                        "button": int(parts[3]),
                        "gesture": gesture,
                    }
                if joy_type == "hat" and len(parts) >= 5:
                    return {
                        "version": 1,
                        "device_kind": "legacy_joystick",
                        "legacy_joy_id": legacy_joy_id,
                        "input_type": "joy_hat",
                        "hat": int(parts[3]),
                        "direction": parts[4],
                        "gesture": gesture,
                    }
            except Exception:
                return None
        return None

    def _load_existing_config(self):
        if not os.path.exists(CONFIG_FILE):
            return
        config = configparser.ConfigParser()
        try:
            config.read(CONFIG_FILE, encoding="utf-8")
        except Exception:
            return

        general_use_shortcuts = None
        general_import_music = None
        general_desktop_shortcut = None
        if config.has_section("General"):
            section = config["General"]
            saved_language = (section.get("language", self.lang) or self.lang).strip().lower()
            if saved_language[:2] in LANGS.values():
                self.lang = saved_language[:2]

            def _general_bool(key):
                try:
                    raw = section.get(key, fallback=None)
                    if raw is None:
                        return None
                    raw = str(raw).strip().lower()
                    if raw in ("1", "yes", "true", "on"):
                        return True
                    if raw in ("0", "no", "false", "off"):
                        return False
                except Exception:
                    pass
                return None

            general_use_shortcuts = _general_bool("use_shortcuts")
            general_import_music = _general_bool("import_music")
            general_desktop_shortcut = _general_bool("desktop_shortcut")
            if general_use_shortcuts is not None:
                self.use_shortcuts.set(general_use_shortcuts)
            if general_import_music is not None:
                self.import_music.set(general_import_music)
            if general_desktop_shortcut is not None:
                self.desktop_sc.set(general_desktop_shortcut)

        if config.has_section("Raccourcis"):
            loaded_any = False
            for key in ["modifier", "suivant", "volume_up", "volume_down", "switch"]:
                binding = self._decode_binding_value(
                    config["Raccourcis"].get(key, ""),
                    modifier=(key == "modifier"),
                )
                if binding is not None:
                    self.raccourcis[key] = binding
                    loaded_any = True
            if general_use_shortcuts is None and loaded_any:
                self.use_shortcuts.set(True)

        legacy_notifications = True
        if config.has_section("Etat"):
            try:
                legacy_notifications = config["Etat"].getboolean("notifications", True)
            except Exception:
                legacy_notifications = True

        self._apply_notification_legacy_default(legacy_notifications)

        if config.has_section("Notifications"):
            section = config["Notifications"]
            def _cfg_bool(key, fallback):
                try:
                    raw = section.get(key, fallback=None)
                    if raw is None:
                        return fallback
                    if isinstance(raw, bool):
                        return raw
                    raw = str(raw).strip().lower()
                    if raw in ("1", "yes", "true", "on"):
                        return True
                    if raw in ("0", "no", "false", "off"):
                        return False
                    return fallback
                except Exception:
                    return fallback

            self.notif_volume.set(_cfg_bool("volume", _cfg_bool("flat_volume", self.notif_volume.get())))
            self.notif_switch.set(
                _cfg_bool("switch", _cfg_bool("flat_switch", _cfg_bool("vr_switch", self.notif_switch.get())))
            )
            self.notif_playlist.set(
                _cfg_bool("playlist", _cfg_bool("flat_playlist", _cfg_bool("vr_playlist", self.notif_playlist.get())))
            )
            self.notif_radio.set(
                _cfg_bool("radio", _cfg_bool("flat_radio", _cfg_bool("vr_radio", self.notif_radio.get())))
            )
            selected_voice = section.get("tts_voice", "").strip()
            matched_voice = _match_tts_voice_name(selected_voice, self._tts_voices)
            if matched_voice:
                self.tts_voice.set(matched_voice)
            elif self._tts_voices and not (self.tts_voice.get() or "").strip():
                self.tts_voice.set(self._tts_voices[0])
        elif self._tts_voices and not (self.tts_voice.get() or "").strip():
            self.tts_voice.set(self._tts_voices[0])

        if config.has_section("Chemins"):
            section = config["Chemins"]
            folders = saver.normalize_music_folders(section.get("music_folders", "").strip())
            legacy_folder = section.get("music_folder", "").strip()
            if legacy_folder:
                folders = saver.normalize_music_folders(folders + [legacy_folder])
            self.music_sources = folders
            if general_import_music is None:
                self.import_music.set(bool(folders))
            elif general_import_music and folders:
                self.import_music.set(True)

        self.notifications_on.set(self._notification_master_enabled())

    # ── HELPERS ──────────────────────────────────────────────────────
    def _clear(self, full=False):
        for w in self.root.winfo_children():
            w.destroy()
        self.root.configure(bg=BG_DARK)
        c = tk.Canvas(self.root, width=WINDOW_WIDTH, height=WINDOW_HEIGHT,
                      highlightthickness=0, bg=BG_DARK)
        c.pack(fill="both", expand=True)
        self._canvas = c
        # Image pleine fenêtre
        photo = _load_bg_image("installer_bg.png", WINDOW_WIDTH, WINDOW_HEIGHT)
        if photo:
            c.create_image(0, 0, anchor="nw", image=photo)
            c._photo = photo
        # Ligne rouge en haut
        c.create_rectangle(0, 0, WINDOW_WIDTH, 4, fill=ACCENT, outline="")
        # Ligne de séparation footer
        c.create_line(0, FOOTER_LINE_Y, WINDOW_WIDTH, FOOTER_LINE_Y, fill=BORDER)
        self._canvas = c
        self._footer_frame = c
        self._content = c   # toujours le canvas — pas de frame opaque intermédiaire
        self._card_y = 100  # position y courante pour placer les cards

    def _header(self, parent):
        c = self._canvas
        c.create_text(350, 40, text=APP_NAME,
                      font=FONT_TITLE, fill=TEXT_WHITE, anchor="center")
        c.create_text(350, 68, text=self.t("title_installer"),
                      font=("Segoe UI", 9, "bold"), fill=ACCENT2, anchor="center")
        c.create_line(42, 92, 658, 92, fill=ACCENT, width=3)
        c.create_line(42, 93, 658, 93, fill=BORDER)
        self._card_y = 108  # y courant pour placer les cards

    def _canvas_card(self, bg=BG_CARD, padx=22, pady=12, gap=8):
        """Crée une Frame card posée directement sur le canvas (image visible autour)."""
        frame = tk.Frame(self._canvas, bg=bg, padx=padx, pady=pady,
                         highlightbackground=BORDER, highlightthickness=1)
        self._canvas.create_window(14, self._card_y + gap, anchor="nw",
                                   window=frame, width=672)
        self._card_y += gap
        return frame

    def _card_advance(self, height, gap=8):
        """Avance la position y de la prochaine card."""
        self._card_y += height + gap

    def _place(self, widget, height, pady=4, fill_x=True):
        """Place un widget sur le canvas et avance _content_y."""
        w = 680 if fill_x else None
        x = 10 if fill_x else 350
        anchor = "nw" if fill_x else "n"
        self._canvas.create_window(x, self._card_y + pady,
                                   anchor=anchor, window=widget,
                                   width=w if fill_x else None)
        self._card_y += height + pady * 2


    def _footer(self, parent, back_cmd=None, next_cmd=None,
                back_text=None, next_text=None, next_color=ACCENT):
        back_text = back_text or self.t("back")
        next_text = next_text or self.t("next")
        c = self._canvas
        if back_cmd:
            btn_back = tk.Button(self.root, text=back_text, font=FONT_BTN,
                                 bg=BG_PANEL, fg=TEXT_WHITE, bd=0,
                                 padx=20, pady=8, cursor="hand2",
                                 activebackground=BORDER,
                                 activeforeground=TEXT_WHITE,
                                 command=back_cmd)
            c.create_window(14, FOOTER_BTN_Y, anchor="w", window=btn_back)
        if next_cmd:
            btn_next = tk.Button(self.root, text=next_text, font=FONT_BTN,
                                 bg=next_color, fg=TEXT_WHITE, bd=0,
                                 padx=20, pady=8, cursor="hand2",
                                 activebackground=ACCENT2,
                                 activeforeground=TEXT_WHITE,
                                 command=next_cmd)
            c.create_window(WINDOW_WIDTH - 14, FOOTER_BTN_Y, anchor="e", window=btn_next)
        if back_cmd:
            btn_back = btn_back  # garder référence
        # (pour compatibilité ancienne signature - dead code supprimé)

    def _card(self, parent, padx=18, pady=7):
        f = tk.Frame(parent, bg=BG_CARD, bd=0,
                     highlightbackground=BORDER, highlightthickness=1)
        f.pack(fill="x", padx=padx, pady=pady)
        return f

    # ── ÉCRAN 0 : Langue ─────────────────────────────────────────────
    def _frame_lang(self):
        self._clear(full=True)
        c = self._canvas

        # Titre
        c.create_text(350, 45, text="▶  ACC PITLANE FM",
                      font=FONT_TITLE, fill=TEXT_WHITE, anchor="center")
        c.create_text(682, 22, text="V1.00 par Metal Slug",
                      font=FONT_SMALL, fill=TEXT_DIM, anchor="ne")
        c.create_line(0, 92, 700, 92, fill=BORDER)

        # Labels langue
        c.create_text(350, 110, text=T["fr"]["lang_title"],
                      font=FONT_STEP, fill=GOLD, anchor="center")
        c.create_text(350, 135, text=T["fr"]["lang_sub"],
                      font=FONT_SMALL, fill=TEXT_GREY, anchor="center")

        # Grille de langues
        initial_lang_name = next(
            (name for name, code in LANGS.items() if code == self.lang),
            "Français",
        )
        self._lang_var = tk.StringVar(value=initial_lang_name)
        langs = list(LANGS.keys())
        btn_w, btn_h = 160, 44
        cols, rows = 2, 4
        start_x = 350 - (cols * btn_w + 10) // 2
        start_y = 165

        for i, lang_name in enumerate(langs):
            row, col = divmod(i, 2)
            x = start_x + col * (btn_w + 20)
            y = start_y + row * (btn_h + 10)
            btn = tk.Radiobutton(
                self.root, text=lang_name, variable=self._lang_var,
                value=lang_name, font=FONT_SUB,
                bg=BG_CARD, fg=TEXT_WHITE, selectcolor=ACCENT,
                activebackground=BG_CARD, activeforeground=TEXT_WHITE,
                cursor="hand2", indicatoron=True, padx=16, pady=10,
                highlightthickness=0)
            c.create_window(x, y, anchor="nw", window=btn, width=btn_w, height=btn_h)

        def _valider():
            self.lang = LANGS[self._lang_var.get()]
            self._frame_welcome()

        ok_btn = tk.Button(self.root, text="OK  →", font=FONT_BTN,
                           bg=ACCENT, fg=TEXT_WHITE, bd=0, padx=30, pady=10,
                           activebackground=ACCENT2, cursor="hand2",
                           command=_valider)
        c.create_window(350, 430, anchor="center", window=ok_btn)


    # ── ÉCRAN 1 : Accueil ────────────────────────────────────────────
    def _frame_welcome(self):
        self._clear()
        self._header(self.root)

        inner = self._canvas_card(gap=10, pady=18)
        tk.Label(inner, text=self.t("welcome"),
                 font=("Segoe UI", 12, "bold"), fg=GOLD, bg=BG_CARD).pack(anchor="w")
        tk.Label(inner, text=APP_NAME,
                 font=FONT_SUB, fg=TEXT_WHITE, bg=BG_CARD).pack(anchor="w", pady=(4, 10))
        for line in self.t("features"):
            tk.Label(inner, text=line, font=FONT_LABEL,
                     fg=TEXT_GREY, bg=BG_CARD, anchor="w", justify="left",
                     wraplength=620).pack(fill="x", pady=2)
        self._card_advance(190)

        self._footer(self.root,
                     back_cmd=self._frame_lang,
                     next_cmd=self._frame_options,
                     next_text=self.t("start"))

    def _frame_options(self):
        self._clear()
        self._header(self.root)

        # Titre
        self._canvas.create_text(14, self._card_y + 4, text=self.t("options"),
                                  font=FONT_STEP, fill=GOLD, anchor="nw")
        self._card_y += 32

        # Card raccourci bureau
        sc = self._canvas_card(gap=4)
        row = tk.Frame(sc, bg=BG_CARD)
        row.pack(fill="x")
        tk.Checkbutton(row, variable=self.desktop_sc, bg=BG_CARD,
                       activebackground=BG_CARD, selectcolor=ACCENT,
                       fg=TEXT_WHITE, font=FONT_SUB, cursor="hand2").pack(side="left")
        tk.Label(row, text=self.t("shortcut"),
                 font=FONT_SUB, fg=TEXT_WHITE, bg=BG_CARD).pack(side="left")
        self._card_advance(44)

        # Card raccourcis contrôleur
        rc = self._canvas_card(gap=4)
        row2 = tk.Frame(rc, bg=BG_CARD)
        row2.pack(fill="x")
