    def _toggle_import(self):
        try:
            self.src_listbox.config(state="normal")
            self.src_add_btn.config(state="normal")
            self.src_remove_btn.config(state="normal")
        except Exception:
            pass

    def _browse_music(self):
        current_selection = None
        try:
            selection = self.src_listbox.curselection()
            if selection:
                current_selection = self.music_sources[selection[0]]
        except Exception:
            current_selection = None
        d = filedialog.askdirectory(
            title=self._playlist_ui_text("playlist_sources"),
            initialdir=current_selection or DEFAULT_MUSIC_SOURCE_DIR or os.path.expanduser("~"))
        if d:
            self.import_music.set(True)
            self.music_sources = saver.normalize_music_folders(self.music_sources + [d])
            self._refresh_music_sources_ui()
            self._toggle_import()

    def _remove_music_source(self):
        try:
            selection = self.src_listbox.curselection()
            if not selection:
                return
            index = selection[0]
            if 0 <= index < len(self.music_sources):
                del self.music_sources[index]
                self._refresh_music_sources_ui()
        except Exception:
            pass

    def _refresh_music_sources_ui(self):
        if not hasattr(self, "src_listbox"):
            return
        self.music_sources = saver.normalize_music_folders(self.music_sources)
        self.src_listbox.config(state="normal")
        self.src_listbox.delete(0, "end")
        for folder in self.music_sources:
            self.src_listbox.insert("end", folder)
        self.src_listbox.selection_clear(0, "end")
        if self.music_sources:
            last = len(self.music_sources) - 1
            self.src_listbox.selection_set(last)
            self.src_listbox.see(last)
        self._toggle_import()
        self.root.update_idletasks()

    def _ensure_default_music_source(self):
        if self.music_sources:
            return
        if os.path.exists(DEFAULT_MUSIC_SOURCE_DIR):
            self.music_sources = [DEFAULT_MUSIC_SOURCE_DIR]
            self.import_music.set(True)

    def _open_music_sources(self):
        targets = saver.normalize_music_folders(self.music_sources)
        for folder in targets:
            if os.path.isdir(folder):
                os.startfile(folder)
                return
        fallback = DEFAULT_MUSIC_SOURCE_DIR if os.path.isdir(DEFAULT_MUSIC_SOURCE_DIR) else os.path.dirname(CONFIG_FILE)
        os.startfile(fallback)

    def _default_radio_resource_files(self):
        exts = (".m3u", ".m3u8", ".pls")
        candidates = []
        if getattr(sys, "frozen", False):
            meipass = getattr(sys, "_MEIPASS", "")
            if meipass:
                candidates.append(meipass)
            candidates.append(os.path.dirname(os.path.abspath(sys.executable)))
        current_dir = os.path.dirname(os.path.abspath(__file__))
        candidates.append(current_dir)
        candidates.append(os.path.abspath(os.path.join(current_dir, "..", "ressource")))

        files = []
        seen = set()
        for folder in candidates:
            if not folder or not os.path.isdir(folder):
                continue
            try:
                names = sorted(os.listdir(folder))
            except Exception:
                continue
            for name in names:
                if not name.lower().endswith(exts):
                    continue
                path = os.path.join(folder, name)
                if not os.path.isfile(path):
                    continue
                key = path.lower()
                if key in seen:
                    continue
                seen.add(key)
                files.append(path)
        return files

    def _sync_default_radios(self):
        copied = 0
        for src in self._default_radio_resource_files():
            dst = os.path.join(RADIO_DIR, os.path.basename(src))
            shutil.copy2(src, dst)
            copied += 1
        return copied

    def _gesture_label(self, gesture: str) -> str:
        labels = {
            "press": ("Appui", "Press"),
            "hold": ("Maintien", "Hold"),
            "double_tap": ("Double tap", "Double tap"),
            "double_tap_hold": ("Double tap maintenu", "Double tap hold"),
        }
        fr, en = labels.get(gesture, (gesture, gesture))
        return en if self.lang == "en" else fr

    def _keyboard_mouse_label(self) -> str:
        return "Keyboard / Mouse" if self.lang == "en" else "Clavier / Souris"

    def _auto_device_label(self) -> str:
        return "Auto-detect" if self.lang == "en" else "Détection auto"

    def _skip_label(self, modifier=False) -> str:
        if modifier:
            return "No modifier" if self.lang == "en" else "Ne pas utiliser de modificateur"
        return "Do not assign" if self.lang == "en" else "Ne pas attribuer cette commande"

    def _guid_joystick(self, js) -> str:
        try:
            return js.get_guid() or ""
        except Exception:
            return ""

    def _vk_from_pygame_event(self, event) -> int:
        scancode = int(getattr(event, "scancode", 0) or 0)
        if not scancode:
            return 0
        try:
            return int(_user32.MapVirtualKeyW(scancode, MAPVK_VSC_TO_VK_EX) or 0)
        except Exception:
            return 0

    def _init_controller_layer(self):
        if not SDL2_CONTROLLER_OK:
            return
        try:
            sdl2_controller.init()
            if hasattr(sdl2_controller, "set_eventstate"):
                sdl2_controller.set_eventstate(True)
        except Exception:
            pass

    def _refresh_device_catalog(self):
        try:
            pygame.joystick.init()
        except Exception:
            pass
        self._init_controller_layer()
        self._device_catalog = [{
            "id": "auto",
            "kind": "auto",
            "label": self._auto_device_label(),
        }, {
            "id": "keyboard_mouse",
            "kind": "keyboard_mouse",
            "label": self._keyboard_mouse_label(),
        }]
        counts = {}
        self._joysticks = []
        self._controllers = []
        for idx in range(pygame.joystick.get_count()):
            try:
                js = pygame.joystick.Joystick(idx)
                js.init()
                guid = self._guid_joystick(js)
                name = js.get_name() or f"Joystick {idx + 1}"
                key = (name, guid)
                occurrence = counts.get(key, 0)
                counts[key] = occurrence + 1
                instance_id = js.get_instance_id() if hasattr(js, "get_instance_id") else idx
                controller_id = None
                if SDL2_CONTROLLER_OK:
                    try:
                        if sdl2_controller.is_controller(idx):
                            ctl = sdl2_controller.Controller(idx)
                            controller_id = int(getattr(ctl, "id", idx))
                            self._controllers.append(ctl)
                    except Exception:
                        controller_id = None
                item = {
                    "id": f"joy::{guid}::{occurrence}::{name}",
                    "kind": "joystick",
                    "label": f"{idx + 1}. {name}",
                    "guid": guid,
                    "name": name,
                    "occurrence": occurrence,
                    "index": idx,
                    "instance_id": instance_id,
                    "controller_id": controller_id,
                }
                self._device_catalog.append(item)
                self._joysticks.append(item)
            except Exception:
                pass

    def _binding_to_device_id(self, binding):
        if not isinstance(binding, dict):
            return "auto"
        if binding.get("device_kind") != "joystick":
            return "keyboard_mouse"
        return f"joy::{binding.get('device_guid', '')}::{int(binding.get('device_occurrence', 0) or 0)}::{binding.get('device_name', '')}"

    def _device_from_id(self, device_id):
        return next((item for item in self._device_catalog if item["id"] == device_id), self._device_catalog[0])

    def _binding_display(self, binding):
        if binding == "skip":
            return "— ignoré —"
        if not isinstance(binding, dict):
            return "— —"

        input_type = binding.get("input_type")
        if input_type == "key":
            label = (binding.get("label") or "").strip()
            if label:
                return f"K: {label.upper()}"
            try:
                return f"K: {pygame.key.name(int(binding.get('key', 0))).upper()}"
            except Exception:
                return "K: ?"
        if input_type == "mouse_button":
            return f"Souris: B{int(binding.get('button', 0))}"
        if input_type in ("joy_button", "controller_button"):
            return f"{binding.get('device_name', 'Joystick')[:14]}: B{int(binding.get('button', 0))}"
        if input_type == "joy_hat":
            return f"{binding.get('device_name', 'Joystick')[:14]}: Hat {binding.get('direction', '?')}"
        if input_type in ("joy_axis", "controller_axis"):
            signe = "+" if binding.get("sign") != "negative" else "-"
            return f"{binding.get('device_name', 'Joystick')[:14]}: Axe {int(binding.get('axis', 0))}{signe}"
        return "— —"

    def _key_label_from_vk(self, vk):
        labels = {
            0x08: "BACKSPACE",
            0x09: "TAB",
            0x0D: "ENTER",
            0x10: "SHIFT",
            0x11: "CTRL",
            0x12: "ALT",
            0x13: "PAUSE",
            0x14: "CAPS LOCK",
            0x1B: "ESC",
            0x20: "SPACE",
            0x21: "PAGE UP",
            0x22: "PAGE DOWN",
            0x23: "END",
            0x24: "HOME",
            0x25: "LEFT",
            0x26: "UP",
            0x27: "RIGHT",
            0x28: "DOWN",
            0x2C: "PRINT SCREEN",
            0x2D: "INSERT",
            0x2E: "DELETE",
            0x5B: "LEFT WIN",
            0x5C: "RIGHT WIN",
            0x60: "NUM 0",
            0x61: "NUM 1",
            0x62: "NUM 2",
            0x63: "NUM 3",
            0x64: "NUM 4",
            0x65: "NUM 5",
            0x66: "NUM 6",
            0x67: "NUM 7",
            0x68: "NUM 8",
            0x69: "NUM 9",
            0x6A: "NUM *",
            0x6B: "NUM +",
            0x6D: "NUM -",
            0x6E: "NUM .",
            0x6F: "NUM /",
            0x90: "NUM LOCK",
            0x91: "SCROLL LOCK",
            0xA0: "LEFT SHIFT",
            0xA1: "RIGHT SHIFT",
            0xA2: "LEFT CTRL",
            0xA3: "RIGHT CTRL",
            0xA4: "LEFT ALT",
            0xA5: "RIGHT ALT",
        }
        if vk in labels:
            return labels[vk]
        try:
            if 0x70 <= vk <= 0x87:
                return f"F{vk - 0x6F}"
            if 0x30 <= vk <= 0x39 or 0x41 <= vk <= 0x5A:
                return chr(vk)
        except Exception:
            pass
        return f"VK {int(vk)}"

    def _keyboard_binding_from_vk(self, vk, gesture):
        vk = int(vk or 0)
        if not vk:
            return None
        return {
            "version": INPUT_BINDING_VERSION,
            "device_kind": "keyboard_mouse",
            "input_type": "key",
            "key": 0,
            "scancode": 0,
            "vk": vk,
            "label": self._key_label_from_vk(vk),
            "gesture": gesture,
        }

    def _capture_keyboard_mouse_snapshot(self):
        keys = []
        mouse_buttons = []
        try:
            for vk in CAPTURE_KEY_VKS:
                if _user32.GetAsyncKeyState(vk) & 0x8000:
                    keys.append(int(vk))
        except Exception:
            keys = []
        try:
            for button, vk in MOUSE_VK_BY_BUTTON.items():
                if _user32.GetAsyncKeyState(vk) & 0x8000:
                    mouse_buttons.append(int(button))
        except Exception:
            mouse_buttons = []
        return {
            "keys": keys,
            "mouse_buttons": mouse_buttons,
        }

    def _binding_from_keyboard_mouse_poll(self, device, gesture, baseline):
        if device["kind"] not in ("auto", "keyboard_mouse"):
            return None
        current = self._capture_keyboard_mouse_snapshot()
        base_keys = set(int(vk) for vk in (baseline.get("keys") or []))
        for vk in current.get("keys", []):
            if int(vk) not in base_keys:
                return self._keyboard_binding_from_vk(vk, gesture)
        base_mouse = set(int(button) for button in (baseline.get("mouse_buttons") or []))
        for button in current.get("mouse_buttons", []):
            if int(button) not in base_mouse:
                return {
                    "version": INPUT_BINDING_VERSION,
                    "device_kind": "keyboard_mouse",
                    "input_type": "mouse_button",
                    "button": int(button),
                    "gesture": gesture,
                }
        return None

    def _binding_physical_signature(self, binding):
        if not isinstance(binding, dict):
            return None
        return (
            binding.get("device_kind"),
            binding.get("device_name"),
            binding.get("device_guid"),
            int(binding.get("device_occurrence", 0) or 0),
            binding.get("legacy_joy_id"),
            binding.get("input_type"),
            binding.get("key"),
            binding.get("vk"),
            binding.get("button"),
            binding.get("hat"),
            binding.get("direction"),
            binding.get("axis"),
            binding.get("sign"),
            round(float(binding.get("threshold", AXIS_CAPTURE_THRESHOLD) or AXIS_CAPTURE_THRESHOLD), 3),
        )

    def _binding_conflict(self, key, binding):
        candidate_sig = self._binding_physical_signature(binding)
        candidate_gesture = binding.get("gesture", "hold" if key == "modifier" else "press")
        for other_key, other_binding in self.raccourcis.items():
            if other_key == key or not isinstance(other_binding, dict):
                continue
            if self._binding_physical_signature(other_binding) != candidate_sig:
                continue
            if key == "modifier" or other_key == "modifier":
                return True
            if other_binding.get("gesture", "press") == candidate_gesture:
                return True
        return False

    def _event_device_id(self, event):
        return getattr(event, "instance_id", getattr(event, "which", getattr(event, "joy", None)))

    def _selected_device_matches(self, device, event):
        if device["kind"] == "auto":
            return event.type in (
                pygame.KEYDOWN,
                pygame.MOUSEBUTTONDOWN,
                pygame.JOYBUTTONDOWN,
                pygame.JOYHATMOTION,
                pygame.JOYAXISMOTION,
                pygame.CONTROLLERBUTTONDOWN,
                pygame.CONTROLLERAXISMOTION,
            )
        if device["kind"] == "keyboard_mouse":
            return event.type in (pygame.KEYDOWN, pygame.MOUSEBUTTONDOWN)
        event_id = self._event_device_id(event)
        return event_id in (device.get("instance_id"), device.get("index"), device.get("controller_id"))

    def _device_for_event(self, event):
        if event.type in (pygame.KEYDOWN, pygame.MOUSEBUTTONDOWN):
            return {"kind": "keyboard_mouse"}
        event_id = self._event_device_id(event)
        return next(
            (
                item for item in self._device_catalog
                if item.get("kind") == "joystick"
                and event_id in (item.get("instance_id"), item.get("index"), item.get("controller_id"))
            ),
            None,
        )

    def _binding_from_event(self, device, event, gesture):
        if device["kind"] == "auto":
            device = self._device_for_event(event)
            if not device:
                return None
        if not self._selected_device_matches(device, event):
            return None

        if device["kind"] == "keyboard_mouse":
            if event.type == pygame.KEYDOWN:
                return {
                    "version": INPUT_BINDING_VERSION,
                    "device_kind": "keyboard_mouse",
                    "input_type": "key",
                    "key": int(event.key),
                    "scancode": int(getattr(event, "scancode", 0) or 0),
                    "vk": self._vk_from_pygame_event(event),
                    "gesture": gesture,
                }
            if event.type == pygame.MOUSEBUTTONDOWN:
                return {
                    "version": INPUT_BINDING_VERSION,
                    "device_kind": "keyboard_mouse",
                    "input_type": "mouse_button",
                    "button": int(event.button),
                    "gesture": gesture,
                }
            return None

        if event.type in (pygame.JOYBUTTONDOWN, pygame.CONTROLLERBUTTONDOWN):
            return {
                "version": INPUT_BINDING_VERSION,
                "device_kind": "joystick",
                "device_name": device["name"],
                "device_guid": device["guid"],
                "device_occurrence": device["occurrence"],
                "input_type": "controller_button" if event.type == pygame.CONTROLLERBUTTONDOWN else "joy_button",
                "button": int(event.button),
                "gesture": gesture,
            }
        if event.type == pygame.JOYHATMOTION and event.value != (0, 0):
            dm = {(0, 1): "up", (0, -1): "down", (-1, 0): "left", (1, 0): "right"}
            return {
                "version": INPUT_BINDING_VERSION,
                "device_kind": "joystick",
                "device_name": device["name"],
                "device_guid": device["guid"],
                "device_occurrence": device["occurrence"],
                "input_type": "joy_hat",
                "hat": int(event.hat),
                "direction": dm.get(event.value, "up"),
                "gesture": gesture,
            }
        if event.type == pygame.JOYAXISMOTION and abs(float(event.value)) >= AXIS_CAPTURE_THRESHOLD:
            return {
                "version": INPUT_BINDING_VERSION,
                "device_kind": "joystick",
                "device_name": device["name"],
                "device_guid": device["guid"],
                "device_occurrence": device["occurrence"],
                "input_type": "joy_axis",
                "axis": int(event.axis),
                "sign": "negative" if float(event.value) < 0 else "positive",
                "threshold": AXIS_CAPTURE_THRESHOLD,
                "gesture": gesture,
            }
        if event.type == pygame.CONTROLLERAXISMOTION and abs(int(event.value)) >= int(AXIS_CAPTURE_THRESHOLD * 32767):
            return {
                "version": INPUT_BINDING_VERSION,
                "device_kind": "joystick",
                "device_name": device["name"],
                "device_guid": device["guid"],
                "device_occurrence": device["occurrence"],
                "input_type": "controller_axis",
                "axis": int(event.axis),
                "sign": "negative" if int(event.value) < 0 else "positive",
                "threshold": AXIS_CAPTURE_THRESHOLD,
                "gesture": gesture,
            }
        return None

    def _open_joystick_for_item(self, item):
        try:
            idx = int(item.get("index", -1))
            if idx < 0 or idx >= pygame.joystick.get_count():
                return None
            js = pygame.joystick.Joystick(idx)
            js.init()
            return js
        except Exception:
            return None

    def _open_controller_for_item(self, item):
        if not SDL2_CONTROLLER_OK:
            return None
        try:
            sdl2_controller.init()
            sdl2_controller.update()
        except Exception:
            return None
        target_index = int(item.get("index", -1))
        target_id = item.get("controller_id")
        indexes = []
        if 0 <= target_index < sdl2_controller.get_count():
            indexes.append(target_index)
        indexes.extend(idx for idx in range(sdl2_controller.get_count()) if idx not in indexes)
        for idx in indexes:
            try:
                if not sdl2_controller.is_controller(idx):
                    continue
                ctl = sdl2_controller.Controller(idx)
                ctl_id = int(getattr(ctl, "id", idx))
                if target_id is None or ctl_id == int(target_id) or idx == target_index:
                    return ctl
            except Exception:
                continue
        return None

    def _capture_joystick_snapshot(self):
        snapshot = {"keyboard_mouse": self._capture_keyboard_mouse_snapshot()}
        try:
            pygame.event.pump()
        except Exception:
            pass
        if SDL2_CONTROLLER_OK:
            try:
                sdl2_controller.update()
            except Exception:
                pass
        controller_button_count = max(0, int(getattr(pygame, "CONTROLLER_BUTTON_MAX", 0) or 0))
        controller_axis_count = max(0, int(getattr(pygame, "CONTROLLER_AXIS_MAX", 0) or 0))
        for item in self._device_catalog:
            if item.get("kind") != "joystick":
                continue
            item_snapshot = {}
            js = self._open_joystick_for_item(item)
            try:
                if js is not None:
                    item_snapshot.update({
                        "buttons": [int(js.get_button(i)) for i in range(js.get_numbuttons())],
                        "hats": [js.get_hat(i) for i in range(js.get_numhats())],
                        "axes": [float(js.get_axis(i)) for i in range(js.get_numaxes())],
                    })
            except Exception:
                pass
            ctl = self._open_controller_for_item(item)
            if ctl is not None:
                try:
                    item_snapshot["controller_buttons"] = [
                        int(ctl.get_button(i)) for i in range(controller_button_count)
                    ]
                except Exception:
                    pass
                try:
                    item_snapshot["controller_axes"] = [
                        int(ctl.get_axis(i)) for i in range(controller_axis_count)
                    ]
                except Exception:
                    pass
            if item_snapshot:
                snapshot[item["id"]] = item_snapshot
        return snapshot

    def _binding_from_polled_input(self, device, gesture, baseline):
        try:
            pygame.event.pump()
        except Exception:
            pass
        if SDL2_CONTROLLER_OK:
            try:
                sdl2_controller.update()
            except Exception:
                pass
        keyboard_binding = self._binding_from_keyboard_mouse_poll(
            device,
            gesture,
            baseline.get("keyboard_mouse", {}) if isinstance(baseline, dict) else {},
        )
        if keyboard_binding:
            return keyboard_binding
        controller_button_count = max(1, int(getattr(pygame, "CONTROLLER_BUTTON_MAX", 0) or 0))
        controller_axis_count = max(0, int(getattr(pygame, "CONTROLLER_AXIS_MAX", 0) or 0))
        controller_axis_threshold = int(AXIS_CAPTURE_THRESHOLD * 32767)
        controller_axis_delta = int(0.2 * 32767)
        targets = self._device_catalog if device["kind"] == "auto" else [device]
        for item in targets:
            if item.get("kind") != "joystick":
                continue
            base = baseline.get(item.get("id"), {}) if isinstance(baseline, dict) else {}
            buttons_base = base.get("buttons") or []
            hats_base = base.get("hats") or []
            axes_base = base.get("axes") or []
            js = self._open_joystick_for_item(item)
            if js is not None:
                try:
                    for idx in range(js.get_numbuttons()):
                        current = int(js.get_button(idx))
                        previous = int(buttons_base[idx]) if idx < len(buttons_base) else 0
                        if current and not previous:
                            return {
                                "version": INPUT_BINDING_VERSION,
                                "device_kind": "joystick",
                                "device_name": item["name"],
                                "device_guid": item["guid"],
                                "device_occurrence": item["occurrence"],
                                "input_type": "joy_button",
                                "button": idx,
                                "gesture": gesture,
                            }
                    for idx in range(js.get_numhats()):
                        current = js.get_hat(idx)
                        previous = hats_base[idx] if idx < len(hats_base) else (0, 0)
                        if current != previous and current != (0, 0):
                            direction_map = {(0, 1): "up", (0, -1): "down", (-1, 0): "left", (1, 0): "right"}
                            return {
                                "version": INPUT_BINDING_VERSION,
                                "device_kind": "joystick",
                                "device_name": item["name"],
                                "device_guid": item["guid"],
                                "device_occurrence": item["occurrence"],
                                "input_type": "joy_hat",
                                "hat": idx,
                                "direction": direction_map.get(current, "up"),
                                "gesture": gesture,
                            }
                    for idx in range(js.get_numaxes()):
                        current = float(js.get_axis(idx))
                        previous = float(axes_base[idx]) if idx < len(axes_base) else 0.0
                        if abs(current) >= AXIS_CAPTURE_THRESHOLD and (
                            abs(previous) < AXIS_CAPTURE_THRESHOLD or abs(current - previous) >= 0.2
                        ):
                            return {
                                "version": INPUT_BINDING_VERSION,
                                "device_kind": "joystick",
                                "device_name": item["name"],
                                "device_guid": item["guid"],
                                "device_occurrence": item["occurrence"],
                                "input_type": "joy_axis",
                                "axis": idx,
                                "sign": "negative" if current < 0 else "positive",
                                "threshold": AXIS_CAPTURE_THRESHOLD,
                                "gesture": gesture,
                            }
                except Exception:
                    pass
            ctl = self._open_controller_for_item(item)
            if ctl is None:
                continue
            controller_buttons_base = base.get("controller_buttons") or []
            controller_axes_base = base.get("controller_axes") or []
            try:
                for idx in range(controller_button_count):
                    current = int(ctl.get_button(idx))
                    previous = int(controller_buttons_base[idx]) if idx < len(controller_buttons_base) else 0
                    if current and not previous:
                        return {
                            "version": INPUT_BINDING_VERSION,
                            "device_kind": "joystick",
                            "device_name": item["name"],
                            "device_guid": item["guid"],
                            "device_occurrence": item["occurrence"],
                            "input_type": "controller_button",
                            "button": idx,
                            "gesture": gesture,
                        }
            except Exception:
                pass
            try:
                for idx in range(controller_axis_count):
                    current = int(ctl.get_axis(idx))
                    previous = int(controller_axes_base[idx]) if idx < len(controller_axes_base) else 0
                    if abs(current) >= controller_axis_threshold and (
                        abs(previous) < controller_axis_threshold or abs(current - previous) >= controller_axis_delta
                    ):
                        return {
                            "version": INPUT_BINDING_VERSION,
                            "device_kind": "joystick",
                            "device_name": item["name"],
                            "device_guid": item["guid"],
                            "device_occurrence": item["occurrence"],
                            "input_type": "controller_axis",
                            "axis": idx,
                            "sign": "negative" if current < 0 else "positive",
                            "threshold": AXIS_CAPTURE_THRESHOLD,
                            "gesture": gesture,
                        }
            except Exception:
                pass
        return None

    def _prepare_shortcut_capture(self):
        try:
            pygame.quit()
        except Exception:
            pass
        pygame.init()
        try:
            if pygame.mixer.get_init():
                pygame.mixer.quit()
        except Exception:
            pass
        _init_pygame_helper_window(self.root, WINDOW_ICON_PNG)
        pygame.event.clear()
        pygame.joystick.init()
        self._init_controller_layer()
        self._refresh_device_catalog()

