    def _build_lord_capture_row(self, parent):
        frame = tk.Frame(parent, bg=BG_CARD)
        frame.pack(fill="x", pady=(4, 0))

        current_binding = self.lord_button_binding if isinstance(self.lord_button_binding, dict) else None
        display_var = tk.StringVar(value=self._binding_display(current_binding))
        err_var = tk.StringVar(value="")

        device_options = {item["id"]: item["label"] for item in self._device_catalog}
        label_to_device = {label: did for did, label in device_options.items()}
        device_label_var = tk.StringVar(
            value=device_options.get(self._binding_to_device_id(current_binding), self._auto_device_label())
        )

        controls = tk.Frame(frame, bg=BG_CARD)
        controls.pack(fill="x", pady=(2, 0))

        device_box = ttk.Combobox(
            controls,
            state="readonly",
            width=22,
            values=list(device_options.values()),
            textvariable=device_label_var,
        )
        device_box.pack(side="left", padx=(0, 6))

        disp = tk.Label(controls, textvariable=display_var,
                        font=("Segoe UI", 8, "bold"), fg=GOLD,
                        bg=BG_PANEL, pady=5, padx=8,
                        highlightbackground=BORDER, highlightthickness=1,
                        anchor="w")
        disp.pack(side="left", fill="x", expand=True, padx=(0, 6))

        btn = tk.Button(controls, text=self.t("assign_btn"),
                        font=FONT_SMALL, bg=BG_PANEL, fg=TEXT_WHITE, bd=0,
                        padx=8, pady=5, cursor="hand2",
                        activebackground=ACCENT, activeforeground=TEXT_WHITE)
        btn.pack(side="left")

        clear_btn = tk.Button(
            controls,
            text=self._shortcut_ui_text("clear_btn"),
            font=FONT_SMALL,
            bg=BG_PANEL,
            fg=TEXT_GREY,
            bd=0,
            padx=8,
            pady=5,
            cursor="hand2",
            activebackground=ACCENT,
            activeforeground=TEXT_WHITE,
        )
        clear_btn.pack(side="left", padx=(6, 0))

        err_lbl = tk.Label(frame, textvariable=err_var,
                           font=("Segoe UI", 8, "bold"), fg=ACCENT,
                           bg="#1a0005", pady=3, padx=8)
        capture_snapshot = {"value": {}}

        def _toggle_err(*_):
            if err_var.get():
                err_lbl.pack(anchor="w", fill="x", pady=(2, 0))
            else:
                err_lbl.pack_forget()
        err_var.trace_add("write", _toggle_err)

        def _start():
            if self._capturing:
                return
            self._capturing = True
            self._refresh_device_catalog()
            capture_snapshot["value"] = self._capture_joystick_snapshot()
            pygame.event.clear()
            err_var.set("")
            display_var.set(self.t("waiting"))
            btn.config(text="...", bg=ACCENT, state="disabled")
            clear_btn.config(state="disabled")
            self.root.after(100, _listen)

        def _clear_binding():
            if self._capturing:
                return
            self.lord_button_binding = None
            display_var.set(self._binding_display(None))
            err_var.set("")

        def _listen():
            if not self._capturing:
                return
            try:
                selected_device = self._device_from_id(label_to_device.get(device_label_var.get(), "keyboard_mouse"))
                events = pygame.event.get([
                    pygame.KEYDOWN,
                    pygame.MOUSEBUTTONDOWN,
                    pygame.JOYBUTTONDOWN,
                    pygame.JOYHATMOTION,
                    pygame.JOYAXISMOTION,
                    pygame.CONTROLLERBUTTONDOWN,
                    pygame.CONTROLLERAXISMOTION,
                ])
                for event in events:
                    binding = self._binding_from_event(selected_device, event, "press")
                    if not binding:
                        continue
                    self._capturing = False
                    self.lord_button_binding = binding
                    display_var.set(self._binding_display(binding))
                    btn.config(text=self.t("assign_btn"), bg=BG_PANEL, state="normal")
                    clear_btn.config(state="normal")
                    return
                binding = self._binding_from_polled_input(selected_device, "press", capture_snapshot["value"])
                if binding:
                    self._capturing = False
                    self.lord_button_binding = binding
                    display_var.set(self._binding_display(binding))
                    btn.config(text=self.t("assign_btn"), bg=BG_PANEL, state="normal")
                    clear_btn.config(state="normal")
                    return
            except Exception:
                pass
            self.root.after(50, _listen)

        btn.config(command=_start)
        clear_btn.config(command=_clear_binding)

